import{c as e,Z as l,Q as r,j as n,o as i,m as o}from"./chunks/framework.qjzPVSkb.js";const L=JSON.parse('{"title":"AI / ML / DL","description":"人工智能、机器学习、深度学习——从大到小的三层包含关系","frontmatter":{"title":"AI / ML / DL","description":"人工智能、机器学习、深度学习——从大到小的三层包含关系","difficulty":"beginner"},"headers":[],"relativePath":"terms/ai-ml-dl.md","filePath":"terms/ai-ml-dl.md"}'),s={name:"terms/ai-ml-dl.md"};function d(h,a,c,p,m,u){const t=l("DifficultyBadge");return r(),n("div",null,[i(t,{level:"beginner"}),a[0]||(a[0]=o(`<h1 id="ai-ml-dl" tabindex="-1">AI / ML / DL <a class="header-anchor" href="#ai-ml-dl" aria-label="Permalink to &quot;AI / ML / DL&quot;">​</a></h1><p>这三个词经常被混用，但它们之间是<strong>包含与被包含</strong>的关系——就像俄罗斯套娃，AI 最大，DL 最小在最里面。</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p><strong>AI（人工智能）</strong> 是让机器模拟人类智能的大目标；<strong>ML（机器学习）</strong> 是 AI 的子集，让机器从数据中自动学习规律而无需手动编程；<strong>DL（深度学习）</strong> 是 ML 的子集，用深层神经网络处理复杂数据。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI（人工智能）</span></span>
<span class="line"><span> └── ML（机器学习）</span></span>
<span class="line"><span>      └── DL（深度学习）</span></span></code></pre></div><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>想象你在教小孩认识动物：</p><ul><li><strong>AI</strong> = &quot;让小孩学会认识动物&quot;这个大目标——你甚至可以用 if-else 规则：四条腿 + 汪汪叫 = 狗。</li><li><strong>ML</strong> = 你不再写死规则，而是给他看 1000 张动物照片并告诉他答案，让他自己在看的过程中总结规律。</li><li><strong>DL</strong> = 你用一个多层神经网络（类似人脑的深度结构），给他看 100 万张照片，他不仅能认出猫狗，还能区分哈士奇和阿拉斯加。</li></ul><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>定义</th><th>典型方法</th></tr></thead><tbody><tr><td>AI</td><td>模拟人类智能的任何系统</td><td>规则系统、搜索算法、ML</td></tr><tr><td>ML</td><td>从数据中学习模式而无需显式编程</td><td>决策树、SVM、随机森林</td></tr><tr><td>DL</td><td>使用多层神经网络进行表征学习</td><td>CNN、RNN、Transformer</td></tr></tbody></table><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— DL 的一个重要应用方向</li><li><a href="/ai-knowledge/terms/training-inference.html">训练 / 推理</a> —— ML/DL 的两个核心阶段</li><li><a href="/ai-knowledge/terms/parameters.html">参数</a> —— DL 模型学到的&quot;知识&quot;</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>俄罗斯套娃——AI 最外层，ML 中间层，DL 最里层。记住：AI 是梦想，ML 是方法，DL 是工具。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://cloud.google.com/learn/artificial-intelligence-vs-machine-learning" target="_blank" rel="noreferrer">AI vs ML vs DL — Google Cloud 官方解释</a></li><li>吴恩达《Machine Learning》课程 —— Coursera 上最经典的 ML 入门课</li></ul>`,16))])}const f=e(s,[["render",d]]);export{L as __pageData,f as default};
